use std::collections::BinaryHeap;

fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    let m = m as usize;
    let n = n as usize;
    let mut dist = vec![vec![vec![i64::MAX; 2]; n]; m];
    dist[0][0][1] = 1;
    let mut pq = BinaryHeap::new();
    pq.push((-1, 0, 0, 1));

    while let Some((neg_cost, i, j, parity)) = pq.pop() {
        let current_cost = -neg_cost;
        if i == m - 1 && j == n - 1 {
            return current_cost;
        }
        if current_cost > dist[i][j][parity] {
            continue;
        }
        if parity == 1 {
            // Move right or down
            if j + 1 < n {
                let new_i = i;
                let new_j = j + 1;
                let new_cost = current_cost + (new_i + 1) * (new_j + 1);
                if new_cost < dist[new_i][new_j][0] {
                    dist[new_i][new_j][0] = new_cost;
                    pq.push((-new_cost, new_i, new_j, 0));
                }
            }
            if i + 1 < m {
                let new_i = i + 1;
                let new_j = j;
                let new_cost = current_cost + (new_i + 1) * (new_j + 1);
                if new_cost < dist[new_i][new_j][0] {
                    dist[new_i][new_j][0] = new_cost;
                    pq.push((-new_cost, new_i, new_j, 0));
                }
            }
        } else {
            // Wait
            let new_cost = current_cost + waitCost[i][j];
            if new_cost < dist[i][j][1] {
                dist[i][j][1] = new_cost;
                pq.push((-new_cost, i, j, 1));
            }
        }
    }
    i64::MAX
}
